Node* deleteMiddle(Node* head) {
    if (head == NULL || head->next == NULL) {
        // Only one node → becomes empty
        return NULL;
    }

    Node* slow = head;
    Node* fast = head;
    Node* prev = NULL;

    // Move slow and fast pointers to find middle
    while (fast != NULL && fast->next != NULL) {
        fast = fast->next->next;
        prev = slow;
        slow = slow->next;
    }

    // Delete middle node
    prev->next = slow->next;
    delete slow;

    return head;
}

