struct Node* deleteMiddle(struct Node* head) {
    if (head == NULL || head->next == NULL) {
        // Empty or single node list -> becomes empty
        return NULL;
    }

    struct Node *slow = head, *fast = head, *prev = NULL;

    while (fast != NULL && fast->next != NULL) {
        fast = fast->next->next;
        prev = slow;
        slow = slow->next;
    }

    // Delete middle node
    prev->next = slow->next;
