function deleteMiddle(head) {
    // If list has 0 or 1 node, delete it (becomes empty)
    if (!head || !head.next) return null;

    let slow = head;
    let fast = head;
    let prev = null;

    // Move fast by 2 and slow by 1
    while (fast && fast.next) {
        fast = fast.next.next;
        prev = slow;
        slow = slow.next;
    }

    // Delete the middle node
    prev.next = slow.next;
    return head;
}
